const authenApi = "http://192.168.1.71:3030/api/users";
const stationApi = "http://192.168.1.71:3030/api";

const TOKEN_KEY = 'aiJwt';

const HEADERS = {
  DEFAULT_HEADER: { "Content-Type": "application/json" },
  JWT_HEADER: () => ({
    "Content-Type": "application/json",
    Authorization: `Bearer ${localStorage.getItem(TOKEN_KEY)}`,
    accept: "application/json",
  }),
};

export const auth = {
  isLoggedIn: () => !!localStorage.getItem(TOKEN_KEY),
  removeToken: () => localStorage.removeItem(TOKEN_KEY),

  login: async (user_name, user_pass) => {
    const res = await fetch(authenApi + "/login", {
      method: "POST",
      headers: HEADERS.DEFAULT_HEADER,
      body: JSON.stringify({ user_name, user_pass }),
    });
    const text = await res.text();
    let data = {};
    try { data = JSON.parse(text); } catch (_) {}
    if (!res.ok) throw new Error(data.message || data.detail || "Sai tài khoản hoặc mật khẩu");
    const payload = data.data ?? data;
    const token = payload.access_token || payload.token || payload.aiJwt;
    if (!token) throw new Error("Không nhận được token từ server");
    localStorage.setItem(TOKEN_KEY, token);
    return token;
  },

  logout: () => { localStorage.removeItem(TOKEN_KEY); window.location.reload(); },
};

export const API = {
  STATIONS: {
    getAll: (page_size =10) => ({
      endPoint: `${stationApi}/stations/?page_size=${page_size}`,
      method: "GET",
      headers: HEADERS.JWT_HEADER(),
    }),
  },
  CONFIG: {
    getAll: (page_size = 10) => ({
      endPoint: `${stationApi}/trungbo-aws-config/?page_size=${page_size}`,
      method: "GET",
      headers: HEADERS.JWT_HEADER(),
    }),
    getById: (station_id) => ({
      endPoint: `${stationApi}/trungbo-aws-config/${station_id}`,
      method: "GET",
      headers: HEADERS.JWT_HEADER(),
    }),
    create: () => ({
      endPoint: `${stationApi}/trungbo-aws-config/`,
      method: "POST",
      headers: HEADERS.JWT_HEADER(),
    }),
    update: (station_id) => ({
      endPoint: `${stationApi}/trungbo-aws-config/${station_id}`,
      method: "PUT",
      headers: HEADERS.JWT_HEADER(),
    }),
    delete: (station_id) => ({
      endPoint: `${stationApi}/trungbo-aws-config/${station_id}`,
      method: "DELETE",
      headers: HEADERS.JWT_HEADER(),
    }),
  },
};

export async function callApi({ endPoint, method, headers }, body = null) {
  const options = { method, headers };
  if (body) options.body = JSON.stringify(body);
  const res = await fetch(endPoint, options);
  if (res.status === 401) { auth.removeToken(); window.location.reload(); return; }
  const text = await res.text();
  let data = {};
  try { data = JSON.parse(text); } catch (_) {}
  if (!res.ok) throw new Error(data.message || data.detail || `Lỗi ${res.status}`);
  return data;
}
